import './App.css';
import SearchBar from './components/SearchBar';
import ErrorMessage from './components/ErrorMessage';
import WeatherCard from './components/WeatherCard';
import Loader from './components/Loader';
import { useEffect, useState } from 'react';

const App = () => {
  const [city, setCity] = useState('');
  const [tcity, setTcity] = useState('');
  const [temperature, setTemperature] = useState('');
  const [wind, setWind] = useState('');
  const [humidity, setHumidity] = useState('');
  const [icon, setIcon] = useState('');

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const API_KEY = "YOUR_API_KEY"; // 🔴 paste your key here

  const fetchWeather = async (cityName) => {
    try {
      setLoading(true);
      setError('');

      const res = await fetch(
        `https://api.weatherapi.com/v1/current.json?key=${API_KEY}&q=${cityName}`
      );

      const data = await res.json();

      if (data.error) {
        setError("City not found");
        return;
      }

      // ✅ Destructuring
      const {
        location: { name },
        current: {
          temp_c,
          humidity,
          wind_kph,
          condition: { icon }
        }
      } = data;

      setTcity(name);
      setTemperature(`Temperature: ${temp_c}°C`);
      setWind(`Wind Speed: ${wind_kph} km/h`);
      setHumidity(`Humidity: ${humidity}%`);
      setIcon(icon);

    } catch (err) {
      setError("Failed to fetch weather");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchWeather("Hyderabad");
  }, []);

  const checkWeather = () => {
    if (!city) {
      setError("Enter city name");
      return;
    }
    fetchWeather(city);
    setCity('');
  };

  return (
    <div className="screen">
      <div className="main">
        <h1>Weather App</h1>

        <SearchBar
          city={city}
          setCity={setCity}
          onSearch={checkWeather}
        />

        {loading && <Loader />}
        {error && <ErrorMessage message={error} />}

        {tcity && !loading && (
          <WeatherCard
            city={tcity}
            icon={icon}
            temperature={temperature}
            wind={wind}
            humidity={humidity}
          />
        )}
      </div>
    </div>
  );
};

export default App;
